ValidationRule.errorConditionFormula:
/* User doesn't have permission, and changed status from Closed to wither working or open*/
AND(
     NOT ($Permission.C_PERM_4100_Change_Interaction_Status )
   , ISCHANGED(Status__c)
   , AND( ISPICKVAL(PRIORVALUE(Status__c),"Closed")
         , OR( ISPICKVAL(Status__c,"Open")
             , ISPICKVAL(Status__c,"Working")
             )
        )
   )
